<?php
if (!defined('ABSPATH')) exit;

/**\n * User Dashboard Shortcode\n * Usage: [fasp_user_dashboard]\n */\nfunction fasp_user_dashboard_shortcode() {\n    if (!is_user_logged_in()) {\n        return '<p>Please <a href=\"' . wp_login_url() . '\">log in</a> to access your dashboard.</p>';\n    }\n\n    $user_id = get_current_user_id();\n    $user = get_user_by('id', $user_id);\n\n    ob_start();\n    ?>\n    <div class=\"fasp-user-dashboard\">\n        <h2>Welcome, <?php echo esc_html($user->display_name); ?>!</h2>\n        \n        <!-- Onboarding Checklist -->\n        <div class=\"fasp-checklist\">\n            <h3>Your Progress</h3>\n            <ul>\n                <li class=\"<?php echo get_user_meta($user_id, '_fasp_email_verified', true) ? 'completed' : ''; ?>\">\n                    <span>Email Verified</span>\n                </li>\n                <li class=\"<?php echo get_user_meta($user_id, '_fasp_profile_complete', true) ? 'completed' : ''; ?>\">\n                    <span>Profile Complete</span>\n                </li>\n                <li class=\"<?php echo get_user_meta($user_id, '_fasp_platform_connected', true) ? 'completed' : ''; ?>\">\n                    <span>Platform Connected</span>\n                </li>\n                <li class=\"<?php echo get_user_meta($user_id, '_fasp_tutorial_completed', true) ? 'completed' : ''; ?>\">\n                    <span>Tutorial Watched</span>\n                </li>\n            </ul>\n        </div>\n\n        <!-- Platforms -->\n        <div class=\"fasp-platforms\">\n            <h3>Available Platforms</h3>\n            <div class=\"platform-grid\">\n                <?php\n                $platforms = fasp_get_visible_platforms($user_id);\n                foreach ($platforms as $platform):\n                ?>\n                    <div class=\"platform-card\">\n                        <h4><?php echo esc_html($platform['name']); ?></h4>\n                        <p>Min Deposit: <?php echo esc_html($platform['min_deposit']); ?></p>\n                        <p>Leverage: 1:<?php echo esc_html($platform['leverage']); ?></p>\n                        <a href=\"<?php echo esc_url($platform['affiliate_link']); ?>\" class=\"button button-primary\">Open Account</a>\n                    </div>\n                <?php\n                endforeach;\n                ?>\n            </div>\n        </div>\n\n        <!-- Resources -->\n        <div class=\"fasp-resources\">\n            <h3>Learning Resources</h3>\n            <?php\n            $resources = get_posts(array(\n                'post_type' => 'fasp_resource',\n                'posts_per_page' => 6,\n            ));\n\n            foreach ($resources as $resource):\n                $download_url = get_post_meta($resource->ID, '_fasp_resource_download_url', true);\n            ?>\n                <div class=\"resource-item\">\n                    <h4><?php echo esc_html($resource->post_title); ?></h4>\n                    <p><?php echo wp_trim_words($resource->post_content, 20); ?></p>\n                    <a href=\"<?php echo esc_url($download_url); ?>\" class=\"button\">Access</a>\n                </div>\n            <?php\n            endforeach;\n            ?>\n        </div>\n\n        <!-- Coaches -->\n        <div class=\"fasp-coaches\">\n            <h3>Meet Our Coaches</h3>\n            <?php\n            $coaches = get_posts(array(\n                'post_type' => 'fasp_coach',\n                'posts_per_page' => 3,\n                'meta_key' => '_fasp_coach_priority',\n                'orderby' => 'meta_value_num',\n                'order' => 'ASC',\n            ));\n\n            foreach ($coaches as $coach):\n                $calendly = get_post_meta($coach->ID, '_fasp_coach_calendly', true);\n            ?>\n                <div class=\"coach-card\">\n                    <?php echo get_the_post_thumbnail($coach->ID, 'thumbnail'); ?>\n                    <h4><?php echo esc_html($coach->post_title); ?></h4>\n                    <p><?php echo wp_trim_words($coach->post_content, 15); ?></p>\n                    <?php if ($calendly): ?>\n                        <a href=\"<?php echo esc_url($calendly); ?>\" target=\"_blank\" class=\"button\">Book Session</a>\n                    <?php endif; ?>\n                </div>\n            <?php\n            endforeach;\n            ?>\n        </div>\n    </div>\n\n    <style>\n    .fasp-user-dashboard {\n        max-width: 1200px;\n        margin: 20px auto;\n    }\n    .fasp-checklist, .fasp-platforms, .fasp-resources, .fasp-coaches {\n        margin: 30px 0;\n    }\n    .platform-grid {\n        display: grid;\n        grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));\n        gap: 20px;\n    }\n    .platform-card, .coach-card {\n        border: 1px solid #ddd;\n        padding: 15px;\n        border-radius: 8px;\n        text-align: center;\n    }\n    .fasp-checklist ul {\n        list-style: none;\n        padding: 0;\n    }\n    .fasp-checklist li {\n        padding: 10px;\n        border-bottom: 1px solid #eee;\n    }\n    .fasp-checklist li.completed span:before {\n        content: \"✓ \";\n        color: green;\n        font-weight: bold;\n    }\n    </style>\n    <?php\n\n    return ob_get_clean();\n}\n\nadd_shortcode('fasp_user_dashboard', 'fasp_user_dashboard_shortcode');
